ee:message.ee:set-payload:
%dw 2.0
output application/json
var email             = (vars.giftJson.person.email default "") as String
var lastName          = (vars.giftJson.person.last_name default "") as String
var mailingCountry    = (vars.giftJson.person.country default  "") as String
var mailingPostalCode = (vars.giftJson.person.postal_code  default "") as String
var transactionId     = (vars.giftJson.pay.external_transaction_id  default "") as String

// Escape single quotes used in SOQL string literals
fun soqlEscape(value: String) = value replace "'" with "\\'"

var contactQuery =
    "SELECT Id,LastName,FirstName,MailingPostalCode,MailingCountry,Email FROM Contact WHERE Email='" ++ soqlEscape(email) ++
    "' OR (LastName='" ++ soqlEscape(lastName) ++
    "' AND MailingCountry='" ++ soqlEscape(mailingCountry) ++
    "' AND MailingPostalCode='" ++ soqlEscape(mailingPostalCode) ++ "')"

var opportunityQuery =
    "SELECT Id,Name,Transaction_Id__c FROM Opportunity WHERE Transaction_Id__c='" ++ soqlEscape(transactionId) ++ "'"

---
{
  allOrNone: true,
  compositeRequest: [
    {
      method: "GET",
      url: "/services/data/v64.0"  ++ "/query/?q=" ++ contactQuery,
      referenceId: "ContactByFields"
    },
    {
      method: "GET",
      url: "/services/data/v64.0" ++ "/query/?q=" ++ opportunityQuery,
      referenceId: "GetOpportunityByTransactionId"
    }
  ]
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json
var contactResponse = (vars.getCompositeResponse.compositeResponse filter ($.referenceId == "ContactByFields"))

var contactRecords =
 if(!isEmpty(contactResponse))
    contactResponse[0].body.records
 else []

var emailMatches =
 contactRecords filter ($.Email == vars.giftJson.person.email)

var fallbackMatches =
 contactRecords filter ($.Email != vars.giftJson.person.email)

---
if(!isEmpty(emailMatches))
 emailMatches[0].Id
else if(!isEmpty(fallbackMatches))
 fallbackMatches[0].Id
else
 ""

set-variable.value:
#[%dw 2.0
output application/json

var region = if (vars.giftJson.pay.currency == "USD") "USA" else "CAN"

---
vars.giftJson
    update {
        case sf_ids at .sf_ids ->
            (sf_ids default {}) ++ {
                sf_contact_id: vars.sfContactId
            }
    }
    ++ {
        opportunity_name: vars.opportunityName,
        region: vars.region
    }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
var base = "/services/data/v64.0"
var contactRef = "UpsertedContact"
var accountQueryRef = "AccountIdfromContact"
var oppRef = "newOpportunity"
var contactMethod = if(vars.sfContactId != "") "PATCH" else "POST"

var contactUrl = if(vars.sfContactId != "") base ++ "/sobjects/Contact/" ++ vars.sfContactId
    else base ++ "/sobjects/Contact"

var contactIdForQuery = if(vars.sfContactId != "") vars.sfContactId else "@{" ++ contactRef ++ ".id}"
var gauAllocation = (
    vars.sfGauAllocation map ((a, idx) ->
      {
        method: "POST",
        url: base ++ "/sobjects/npsp_Allocation__c",
        referenceId: "newAllocation" ++ ((idx + 1) as String),
        body:
          a
          ++ {
            npsp_Opportunity__c: "@{" ++ oppRef ++ ".id}"
          }
      }
    )
  )
---
{
  allOrNone: true,
  compositeRequest:

  [

    // CONTACT
    {
     method: contactMethod,
     url: contactUrl,
     referenceId: contactRef,
     body: vars.sfContactInsert.Contact
},

    // GET ACCOUNT FROM CONTACT
    {
     method: "GET",
     url: base ++ "/query/?q=SELECT Id, AccountId FROM Contact WHERE Id='" ++ contactIdForQuery ++ "'",
     referenceId: accountQueryRef
},

    // OPPORTUNITY
    {
      method: "POST",
      url: base ++ "/sobjects/Opportunity",
      referenceId: oppRef,
      body: vars.sfOpportunityUpsert.Opportunity
        ++ {
          AccountId: "@{" ++ accountQueryRef ++ ".records[0].AccountId}",
          npsp_Primary_Contact__c: "@{" ++ accountQueryRef ++ ".records[0].Id}"
        }
    }


  ] ++ gauAllocation

}
